// Demonstrate the difference between decodable and causal
const scenarios = [
  {
    sentence: 'The cop shot Frank',
    operator: 'HARM',
    predicted: ['hospital', 'injury', 'pain'],
    probeScore: 0.94,
    causalTest: 'Swap HARM→ATRANS subspace'
  },
  {
    sentence: 'The teacher gave Mary a book',
    operator: 'ATRANS',
    predicted: ['possession', 'reading', 'thanks'],
    probeScore: 0.91,
    causalTest: 'Swap ATRANS→HARM subspace'
  }
];

let html = '<div style="font-family:system-ui;font-size:13px">';
html += '<b>🔬 Two Levels of Evidence:</b><br><br>';
html += '<table style="border-collapse:collapse;width:100%">';
html += '<tr style="background:#1e293b"><th style="padding:6px;text-align:left">Test</th><th>Probe (correlation)</th><th>DII (causation)</th></tr>';

scenarios.forEach(s => {
  html += `<tr style="border-top:1px solid #334155">`;
  html += `<td style="padding:6px">"${s.sentence}"<br><span style="color:#60a5fa">${s.operator}</span></td>`;
  html += `<td style="padding:6px;text-align:center"><span style="color:#4ade80">${s.probeScore}</span><br><span style="font-size:11px;color:#94a3b8">Can decode operator ✓</span></td>`;
  html += `<td style="padding:6px;text-align:center"><span style="color:#f59e0b">?</span><br><span style="font-size:11px;color:#94a3b8">${s.causalTest}</span></td>`;
  html += '</tr>';
});

html += '</table><br>';
html += '<div style="background:#1e3a5f;padding:8px;border-radius:6px;font-size:12px">';
html += '<b>The key question:</b> After swapping the HARM subspace from sentence 1 into sentence 2, does the model predict injury/hospital for the giving sentence? If yes → operators are <b>causally real</b>.';
html += '</div></div>';
return html;

// Visualize subspace intervention in 2D
const W = 400, H = 350;
let svg = `<svg width="${W}" height="${H}" style="background:#0f172a;border-radius:8px">`;

// Two activation vectors
const harm = {x: 280, y: 80, label: 'h_HARM', color: '#ef4444'};
const atrans = {x: 120, y: 260, label: 'h_ATRANS', color: '#3b82f6'};

// Draw operator subspace axis (diagonal)
svg += `<line x1="50" y1="310" x2="350" y2="40" stroke="#4ade80" stroke-width="1" stroke-dasharray="6,4" opacity="0.5"/>`;
svg += `<text x="355" y="35" fill="#4ade80" font-size="11">Operator</text>`;
svg += `<text x="355" y="48" fill="#4ade80" font-size="11">subspace</text>`;

// Draw context subspace axis (perpendicular)
svg += `<line x1="50" y1="40" x2="350" y2="310" stroke="#94a3b8" stroke-width="1" stroke-dasharray="6,4" opacity="0.3"/>`;
svg += `<text x="355" y="305" fill="#94a3b8" font-size="11">Context</text>`;

// Original points
[harm, atrans].forEach(p => {
  svg += `<circle cx="${p.x}" cy="${p.y}" r="8" fill="${p.color}"/>`;
  svg += `<text x="${p.x+12}" y="${p.y+4}" fill="${p.color}" font-size="12" font-weight="bold">${p.label}</text>`;
});

// Intervened point: ATRANS context + HARM operator
const swap = {x: 200, y: 120};
svg += `<circle cx="${swap.x}" cy="${swap.y}" r="8" fill="#f59e0b" stroke="#fff" stroke-width="2"/>`;
svg += `<text x="${swap.x+12}" y="${swap.y+4}" fill="#f59e0b" font-size="12" font-weight="bold">h_swapped</text>`;

// Arrows showing the swap
svg += `<line x1="${harm.x}" y1="${harm.y}" x2="${swap.x+5}" y2="${swap.y-5}" stroke="#ef4444" stroke-width="1.5" stroke-dasharray="4,3" marker-end="url(#arr)"/>`;
svg += `<line x1="${atrans.x}" y1="${atrans.y}" x2="${swap.x-5}" y2="${swap.y+5}" stroke="#3b82f6" stroke-width="1.5" stroke-dasharray="4,3" marker-end="url(#arr2)"/>`;

// Arrow markers
svg += '<defs><marker id="arr" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M 0 0 L 10 5 L 0 10 z" fill="#ef4444"/></marker>';
svg += '<marker id="arr2" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M 0 0 L 10 5 L 0 10 z" fill="#3b82f6"/></marker></defs>';

// Labels
svg += `<text x="130" y="140" fill="#ef4444" font-size="10" opacity="0.8">operator from HARM →</text>`;
svg += `<text x="80" y="220" fill="#3b82f6" font-size="10" opacity="0.8">← context from ATRANS</text>`;

// Legend
svg += `<text x="20" y="340" fill="#f59e0b" font-size="11">⚡ h_swapped = ATRANS context + HARM operator → predicts injury!</text>`;

svg += '</svg>';
return svg;

// Hypothetical alignment scores for different operator inventories
const theories = [
  {name: 'Schank-11', score: 0.82, k: 8, color: '#4ade80', note: 'Fine-grained, good alignment'},
  {name: 'Dowty-4', score: 0.71, k: 3, color: '#60a5fa', note: 'Coarse but efficient'},
  {name: 'Discovered-7', score: 0.88, k: 6, color: '#f59e0b', note: 'Data-driven optimal?'},
  {name: 'Random-11', score: 0.34, k: 8, color: '#ef4444', note: 'Control (should fail)'},
];

let html = '<div style="font-family:system-ui;font-size:13px">';
html += '<b>🏆 Interchange Intervention Accuracy by Operator Theory</b><br>';
html += '<span style="font-size:11px;color:#94a3b8">(Hypothetical — illustrating the experimental design)</span><br><br>';

theories.forEach(t => {
  const barW = Math.round(t.score * 280);
  html += `<div style="margin:6px 0">`;
  html += `<span style="display:inline-block;width:110px;color:${t.color}">${t.name}</span>`;
  html += `<span style="display:inline-block;width:${barW}px;height:20px;background:${t.color};border-radius:3px;opacity:0.7"></span>`;
  html += ` <span style="color:#e2e8f0">${(t.score*100).toFixed(0)}%</span>`;
  html += `<span style="color:#94a3b8;font-size:11px"> (k=${t.k})</span>`;
  html += `<br><span style="font-size:11px;color:#64748b;margin-left:110px">${t.note}</span>`;
  html += '</div>';
});

html += '<br><div style="background:#1e3a5f;padding:8px;border-radius:6px;font-size:12px">';
html += '<b>Key metric:</b> What % of interchange interventions produce the output predicted by the high-level model? Higher = more faithful abstraction. Random-11 should score near chance.';
html += '</div></div>';
return html;
